import React from 'react';
import { Link } from 'react-router-dom';

function Services() {
  const serviceData = [
    { id: 1, title: "Web Development", color: "#0d6efd", img: "https://images.unsplash.com", icon: "fas fa-code", desc: "Building high-speed, futuristic websites that convert visitors into customers." },
    { id: 2, title: "UI/UX Design", color: "#dc3545", img: "https://images.unsplash.com", icon: "fas fa-bezier-curve", desc: "Pixel-perfect designs focused on user psychology and modern digital aesthetics." },
    { id: 3, title: "App Development", color: "#198754", img: "https://images.unsplash.com", icon: "fas fa-mobile-alt", desc: "Powerful native and cross-platform apps with seamless and smooth user experiences." },
    { id: 4, title: "Assignment Support", color: "#ffc107", img: "https://images.unsplash.com", icon: "fas fa-book-reader", desc: "Expert academic guidance to help you excel in your technical projects and finals." },
    { id: 5, title: "PPT Design", color: "#0dcaf0", img: "https://images.unsplash.com", icon: "fas fa-file-powerpoint", desc: "High-impact visual storytelling that makes your presentations truly unforgettable." },
    { id: 6, title: "Report Writing", color: "#6c757d", img: "https://images.unsplash.com", icon: "fas fa-file-alt", desc: "Professional, data-driven technical reports and structured business documentation." },
    { id: 7, title: "Digital Marketing", color: "#343a40", img: "https://images.unsplash.com", icon: "fas fa-bullhorn", desc: "Strategic growth campaigns to enhance your online presence and market reach." },
    { id: 8, title: "Content Writing", color: "#0d6efd", img: "https://images.unsplash.com", icon: "fas fa-pen-nib", desc: "Engaging and SEO-optimized content that speaks your brand's unique voice." },
    { id: 9, title: "SEO Optimization", color: "#20c997", img: "https://images.unsplash.com", icon: "fas fa-search-plus", desc: "Improve your search engine rankings and attract organic traffic with ease." }
  ];

  return (
    <div className="services-page py-5 bg-white">
      <div className="container">
        
        {/* Header Section */}
        <div className="text-center mb-5 pb-3">
          <h2 className="fw-bold display-4 text-dark mb-3">Our <span className="text-primary">Premium</span> Services</h2>
          <p className="text-muted fs-5 mx-auto" style={{ maxWidth: '700px' }}>Innovative and tailored digital solutions built for visionaries and successful businesses.</p>
          <div className="header-bar mx-auto"></div>
        </div>

        {/* 9 Professional Image Cards */}
        <div className="row g-4">
          {serviceData.map((service) => (
            <div className="col-lg-4 col-md-6" key={service.id}>
              <div className="card h-100 border-0 shadow-sm pro-card">
                
                {/* Image Section with Overlay */}
                <div className="position-relative overflow-hidden card-img-box">
                  <img src={service.img} alt={service.title} className="card-img-top pro-image" />
                  <div className="card-badge" style={{ backgroundColor: service.color }}>
                    <i className={service.icon}></i>
                  </div>
                </div>

                {/* Content Section */}
                <div className="card-body p-4 bg-white rounded-bottom-4">
                  <h4 className="fw-bold text-dark mb-3 h5">{service.title}</h4>
                  <p className="text-muted small mb-4 px-1" style={{ lineHeight: '1.6' }}>{service.desc}</p>
                  
                  <Link to="/register" className="btn btn-outline-dark w-100 rounded-pill fw-bold py-2 start-btn">
                    Get Started <i className="fas fa-arrow-right ms-2 small"></i>
                  </Link>
                </div>

              </div>
            </div>
          ))}
        </div>
      </div>

      {/* --- PROFESSIONAL CSS --- */}
      <style>{`
        @import url('https://fonts.googleapis.com');

        .services-page { font-family: 'Outfit', sans-serif; }
        
        .header-bar { width: 50px; height: 5px; background: #0d6efd; border-radius: 10px; }

        .pro-card {
          border-radius: 24px;
          transition: all 0.4s cubic-bezier(0.165, 0.84, 0.44, 1);
          background: #fff;
          overflow: hidden;
        }

        .card-img-box { height: 200px; }
        
        .pro-image {
          width: 100%;
          height: 100%;
          object-fit: cover;
          transition: transform 0.6s ease;
        }

        .card-badge {
          position: absolute;
          top: 15px;
          right: 15px;
          width: 45px;
          height: 45px;
          border-radius: 12px;
          display: flex;
          align-items: center;
          justify-content: center;
          color: white;
          font-size: 1.2rem;
          box-shadow: 0 8px 15px rgba(0,0,0,0.1);
          z-index: 2;
        }

        .pro-card:hover {
          transform: translateY(-12px);
          box-shadow: 0 30px 60px rgba(0,0,0,0.08) !important;
        }

        .pro-card:hover .pro-image {
          transform: scale(1.1);
        }

        .start-btn {
          border-color: #eee;
          transition: 0.3s;
          font-size: 0.85rem;
        }

        .start-btn:hover {
          background-color: #0d6efd !important;
          border-color: #0d6efd !important;
          color: #fff !important;
        }

        @media (max-width: 768px) {
          .display-4 { font-size: 2rem; }
        }
      `}</style>
    </div>
  );
}

export default Services;
